<?php session_start(); if (!isset($_SESSION['user_id']) || $_SESSION['role'] != 'Faculty') { header("Location: index.php"); exit(); } require_once 'config/database.php'; $success = ""; $error = ""; if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_FILES['handout'])) { $title = $_POST['title']; $file = $_FILES['handout']; $allowed = ['pdf', 'jpg', 'jpeg', 'png']; $ext = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION)); if (in_array($ext, $allowed) && $file['size'] < 10485760) { $filename = uniqid() . '.' . $ext; if (move_uploaded_file($file['tmp_name'], 'uploads/' . $filename)) { $query = "INSERT INTO faculty_uploads (title, file_name, uploaded_by, uploaded_at) VALUES (?, ?, ?, NOW())"; $stmt = $conn->prepare($query); $stmt->bind_param("sss", $title, $filename, $_SESSION['email']); if ($stmt->execute()) { $success = "File uploaded!"; } } } else { $error = "Invalid file!"; } } if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['notify'])) { $title = $_POST['notif_title']; $message = $_POST['notif_message']; $query = "INSERT INTO notifications (title, message, created_at, posted_by) VALUES (?, ?, NOW(), ?)"; $stmt = $conn->prepare($query); $stmt->bind_param("sss", $title, $message, $_SESSION['email']); $stmt->execute(); $success = "Notification posted!"; } $files_query = "SELECT * FROM faculty_uploads WHERE uploaded_by = ? ORDER BY uploaded_at DESC"; $files_stmt = $conn->prepare($files_query); $files_stmt->bind_param("s", $_SESSION['email']); $files_stmt->execute(); $files_result = $files_stmt->get_result(); $feedback_query = "SELECT * FROM feedback ORDER BY created_at DESC"; $feedback_result = $conn->query($feedback_query); ?> <!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Faculty Dashboard</title><link rel="stylesheet" href="assets/css/style.css"></head><body><?php include 'includes/header.php'; ?><main class="container"><h1>Faculty Dashboard</h1><?php if ($success) echo "<div class='alert alert-success'>$success</div>"; if ($error) echo "<div class='alert alert-error'>$error</div>"; ?><div class="grid-2"><div class="card"><h2>Upload Handout</h2><form method="POST" enctype="multipart/form-data"><input type="text" name="title" class="form-input" placeholder="Title" required><input type="file" name="handout" class="form-input" accept=".pdf,.jpg,.jpeg,.png" required><button type="submit" class="btn btn-primary">Upload</button></form></div><div class="card"><h2>Post Notification</h2><form method="POST"><input type="text" name="notif_title" class="form-input" placeholder="Title" required><textarea name="notif_message" class="form-input" rows="3" placeholder="Message" required></textarea><button type="submit" class="btn btn-primary" name="notify">Post</button></form></div></div><div class="card"><h2>Your Files</h2><table class="table"><tr><th>Title</th><th>Date</th><th>Action</th></tr><?php while($f = $files_result->fetch_assoc()): ?><tr><td><?php echo $f['title']; ?></td><td><?php echo date("M d, Y", strtotime($f['uploaded_at'])); ?></td><td><a href="backend/file-download.php?file_id=<?php echo $f['id']; ?>" class="btn btn-primary btn-sm">Download</a></td></tr><?php endwhile; ?></table></div><div class="card"><h2>Student Feedback</h2><?php while($fb = $feedback_result->fetch_assoc()): ?><div class="feedback-item"><strong><?php echo $fb['student_email']; ?>:</strong> <?php echo $fb['message']; ?></div><?php endwhile; ?></div></main><?php include 'includes/footer.php'; ?></body></html>